import { useEffect, useState } from "react";
import swal from 'sweetalert';
import { HashRouter, Link, Routes, Route} from "react-router-dom";
import Adduser from "./adduser";
import React from 'react';
import Details from './details';

const Userlist = () =>{
    let [userlist, picklist] = useState([]);

    const logout = () =>{
        localStorage.clear();
        window.location.href="http://localhost:3000/#/"; // it will go to dashboard
        window.location.reload(); // it will reload the app. js(window) file
        
        //other method - window.location.href="http://localhost:3000/#/";
    }

    const getusers = () =>{
        let url = "http://localhost:3333/user";
        fetch(url)
        .then(responsedata => responsedata.json())
        .then(data => {
            picklist(data);
        })
     }

     const deleteuser = (id) =>{
        let url = "http://localhost:2222/user/"+id;
      let postoption = {method: "DELETE"};
      fetch(url, postoption)
      .then(response => response.json())
      .then(Array =>{
         alert(Array.message);
         window.location.reload();
           })
     }

     const showdetails = (id) =>{
        let url = "http://localhost:3333/user/"+id;
        fetch(url)
        .then(responsedata => responsedata.json())
        .then(data => {
           
        })
     }

    useEffect(()=>{
        getusers();
    },[1])

    return (
        <section>
            <nav className="navbar navbar-expand-lg bg-dark sticky-top p-3">
            <div className="container-fluid">
              <a className="navbar-brand text-white" href="#">  User Management System</a>
              <button className="navbar-toggler" type="button" data-bs-toggle="collapse" data-bs-target="#navbarSupportedContent" aria-controls="navbarSupportedContent" aria-expanded="false" aria-label="Toggle navigation">
                <span className="navbar-toggler-icon"></span>
              </button>
              <div className="collapse navbar-collapse" id="navbarSupportedContent">
                <ul className="navbar-nav ms-auto mb-2 mb-lg-0">
                    {/* by using ms-auto ul will be shifted to right and by writing mx-auto ul will be shifted to middle */}
                 
                    <li className="nav-item me-5">
                 <Link className="nav-link btn btn-warning text-white" to="/adduser"><i className='fa fa-plus'></i>  Add User</Link>
                 </li>

                  <li className="nav-item me-5">
                  <label className="text-danger" onClick={logout}> Welcome - {localStorage.getItem("fullname") } Logout <i className="fa fa-power-off"></i>  </label>
                  </li>
    
                  <li className="nav-item me-5">
                    
                  </li>
                </ul>
                
              </div>
            </div>
          </nav>
           
      
   
     

      <div className="container mt-4">
        <div className="row">
     {
           
          userlist.map((user, index) => {
           
            return (
                <div class="col-lg-3 mb-4" key={index} >
                   <div class="card" onClick={showdetails(this, user._id)}>
                    <div class="card-header bg-primary text-white text-right">
                    <i class="fa-solid fa-trash-can p-3" onClick={deleteuser.bind(this, user._id)}></i>
                    <Link to={`/edituser/${user._id}`}>  <i class="fa-regular fa-pen-to-square" ></i> </Link> 
                    </div>
                    <div class="card-body">
                      <div className="col-lg-3 mb-4 " key={index}>
                        <div className="p-3 text-center shadow">
                            <p className="mb-3"> {user.name} </p>
                            <p className="mb-3"> {user.email} </p>
                            <p className="mb-3">Rs. {user.mobile} </p>
                       </div>
                      </div>
                    </div>
                    <div class="card-footer bg-dark text-white text-center"> 
                      
                    </div>
                   </div>
                </div>
             
            );
          
       })
      }
        </div>
      </div>
      </section>
    );
    }

export default Userlist;
